create extension if not exists "uuid-ossp";
create type public.user_role as enum ('user','moderator','admin');
create type public.review_status as enum ('pending','approved','rejected');
create type public.report_status as enum ('pending','resolved','dismissed');

create table if not exists public.profiles (id uuid primary key default uuid_generate_v4(),user_id uuid unique not null,email text not null unique,nickname text,region text not null,role public.user_role not null default 'user',created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.news_articles (id uuid primary key default uuid_generate_v4(),title text not null,source_name text not null,summary text not null,source_url text not null,category text not null,published_date date not null,is_featured boolean not null default false,is_visible boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.notices (id uuid primary key default uuid_generate_v4(),title text not null,content text not null,is_pinned boolean not null default false,is_visible boolean not null default true,created_by uuid references public.profiles(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.board_categories (id uuid primary key default uuid_generate_v4(),name text not null unique,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.posts (id uuid primary key default uuid_generate_v4(),category_id uuid references public.board_categories(id),author_id uuid references public.profiles(id),title text not null,content text not null,region text,view_count int not null default 0,like_count int not null default 0,is_hidden boolean not null default false,is_deleted boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.comments (id uuid primary key default uuid_generate_v4(),post_id uuid references public.posts(id),author_id uuid references public.profiles(id),content text not null,is_deleted boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.reports (id uuid primary key default uuid_generate_v4(),target_type text not null,target_id uuid not null,reporter_id uuid references public.profiles(id),reason text not null,status public.report_status not null default 'pending',created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.politicians (id uuid primary key default uuid_generate_v4(),name text not null,party text not null,district text not null,summary text not null,speech_date date,source_url text not null,review_status public.review_status not null default 'pending',is_visible boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.politician_sources (id uuid primary key default uuid_generate_v4(),politician_id uuid references public.politicians(id),source_title text not null,source_url text not null,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.resources (id uuid primary key default uuid_generate_v4(),title text not null,description text,category text not null,file_url text not null,file_type text not null,file_size bigint not null,is_visible boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.events (id uuid primary key default uuid_generate_v4(),title text not null,description text,location text not null,start_date timestamptz not null,end_date timestamptz,is_visible boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.newsletter_subscribers (id uuid primary key default uuid_generate_v4(),email text unique not null,region text,is_active boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.faq_items (id uuid primary key default uuid_generate_v4(),question text not null,answer text not null,sort_order int not null default 0,is_visible boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.timeline_items (id uuid primary key default uuid_generate_v4(),title text not null,description text,timeline_date date not null,status text not null,sort_order int not null default 0,is_visible boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.attachments (id uuid primary key default uuid_generate_v4(),target_type text not null,target_id uuid not null,file_name text not null,file_url text not null,file_type text not null,file_size bigint not null,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.volunteer_applications (id uuid primary key default uuid_generate_v4(),name text,email text not null,region text not null,message text,status text not null default 'pending',created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.submissions (id uuid primary key default uuid_generate_v4(),type text not null,email text not null,region text,title text,content text,status text not null default 'pending',created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.site_settings (id uuid primary key default uuid_generate_v4(),key text unique not null,value jsonb not null,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.audit_logs (id uuid primary key default uuid_generate_v4(),actor_id uuid references public.profiles(id),action text not null,target_type text not null,target_id uuid,metadata jsonb,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create index if not exists idx_news_category_date on public.news_articles (category, published_date desc);
create index if not exists idx_posts_category_created on public.posts (category_id, created_at desc);
create index if not exists idx_reports_status on public.reports (status);
create index if not exists idx_politicians_review on public.politicians (review_status, is_visible);
create index if not exists idx_events_start_date on public.events (start_date);
alter table public.profiles enable row level security;alter table public.posts enable row level security;alter table public.news_articles enable row level security;
create policy "public news readable" on public.news_articles for select using (is_visible = true);
create policy "public posts readable" on public.posts for select using (is_deleted = false and is_hidden = false);
create policy "users manage own posts" on public.posts for all using (auth.uid() = author_id) with check (auth.uid() = author_id);
-- storage: public-files bucket, allowed pdf,jpg,jpeg,png,webp,docx, max 10MB
